from contextlib import contextmanager


class InsufficientFunds(ValueError):
    pass


class WalletStore:
    def __init__(self):
        self._wallets = {}

    def create(self, wallet_id, balance, currency="USD"):
        self._wallets[wallet_id] = {
            "balance": balance,
            "currency": currency,
        }

    def balance(self, wallet_id):
        return self._wallets[wallet_id]["balance"]

    def deposit(self, wallet_id, amount):
        self._wallets[wallet_id]["balance"] += amount

    def move(self, source, destination, amount):
        if amount <= 0:
            raise ValueError("amount must be positive")
        source_wallet = self._wallets[source]
        destination_wallet = self._wallets[destination]
        if source_wallet["currency"] != destination_wallet["currency"]:
            raise ValueError("currency mismatch")
        if source_wallet["balance"] < amount:
            raise InsufficientFunds(source)
        source_wallet["balance"] -= amount
        destination_wallet["balance"] += amount

    @contextmanager
    def atomic(self):
        snapshot = self._wallets.copy()
        try:
            yield
        except Exception:
            self._wallets = snapshot
            raise

