class JournalWriteError(RuntimeError):
    pass


class Journal:
    def __init__(self):
        self.entries = []
        self.fail_once_for = set()
        self.blocked_destinations = set()

    def record_transfer(self, request_id, source, destination, amount):
        debit = {
            "request_id": request_id,
            "wallet": source,
            "delta": -amount,
        }
        credit = {
            "request_id": request_id,
            "wallet": destination,
            "delta": amount,
        }
        self.entries.append(debit)
        if request_id in self.fail_once_for:
            self.fail_once_for.remove(request_id)
            raise JournalWriteError("adapter failed after debit")
        if destination in self.blocked_destinations:
            raise JournalWriteError("destination unavailable")
        self.entries.append(credit)

    def entries_for(self, request_id):
        return [entry for entry in self.entries if entry["request_id"] == request_id]

