class TransferService:
    def __init__(self, wallets, journal):
        self._wallets = wallets
        self._journal = journal
        self._results = {}

    def transfer(self, request_id, source, destination, amount):
        if request_id in self._results:
            return dict(self._results[request_id])

        self._results[request_id] = {
            "request_id": request_id,
            "status": "accepted",
        }
        with self._wallets.atomic():
            self._wallets.move(source, destination, amount)
            self._journal.record_transfer(
                request_id,
                source,
                destination,
                amount,
            )

        result = {
            "request_id": request_id,
            "status": "committed",
            "source_balance": self._wallets.balance(source),
            "destination_balance": self._wallets.balance(destination),
        }
        self._results[request_id] = result
        return dict(result)
